const parent = document.getElementById('viz');
const host = document.createElement('div'); host.style.cssText='display:block;width:100%';
const root = host.attachShadow({mode:'open'});
const CSS = `

:host{display:block;width:100%;--_bg:var(--ov-bg,#fff);--_raised:var(--ov-bg,#fff);--_text:var(--ov-text,#1f2933);--_muted:var(--ov-muted,#6b7280);--_line:var(--ov-line,#e5e7eb);--_accent:var(--ov-accent,#4f46e5);--_ok:var(--ov-ok,#0f9d58);--_no:var(--ov-no,#e11d48);--_partial:var(--ov-partial,#d97706);--_soft:#f8fafc;--_accent-soft:#eef2ff;color:var(--_text);font-family:ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;font-variant-numeric:tabular-nums;-webkit-font-smoothing:antialiased}
:host([hidden]){display:none}
*{box-sizing:border-box}
.frame{overflow:hidden;border:1px solid var(--_line);border-radius:18px;background:var(--_bg);box-shadow:0 12px 32px rgba(15,23,42,.07)}
.heading{padding:20px 22px 17px;border-bottom:1px solid var(--_line);background:var(--_soft)}
.eyebrow{margin:0 0 6px;color:var(--_accent);font-size:11px;font-weight:800;letter-spacing:.13em;text-transform:uppercase}
h2{margin:0;font-size:clamp(18px,3vw,24px);font-weight:750;letter-spacing:-.02em;line-height:1.2}
.subtitle{margin-top:6px;color:var(--_muted);font-size:12px;line-height:1.45}
.list{display:flex;flex-wrap:wrap;gap:10px;padding:18px 20px 20px}
.pill{display:inline-flex;min-height:34px;align-items:center;gap:7px;padding:7px 11px;border:1px solid transparent;border-radius:999px;font-size:12px;font-weight:720;line-height:1}
.icon{display:inline-grid;width:17px;height:17px;place-items:center;border-radius:999px;font-size:10px;font-weight:900}
.pill.success{border-color:color-mix(in srgb,var(--_ok) 24%,var(--_line));background:color-mix(in srgb,var(--_ok) 11%,var(--_bg));color:var(--_ok)}
.pill.success .icon{background:var(--_ok);color:#fff}
.pill.danger{border-color:color-mix(in srgb,var(--_no) 23%,var(--_line));background:color-mix(in srgb,var(--_no) 10%,var(--_bg));color:var(--_no)}
.pill.danger .icon{background:var(--_no);color:#fff}
.pill.warning{border-color:color-mix(in srgb,var(--_partial) 26%,var(--_line));background:color-mix(in srgb,var(--_partial) 12%,var(--_bg));color:var(--_partial)}
.pill.warning .icon{background:var(--_partial);color:#fff}
.pill.info{border-color:color-mix(in srgb,var(--_accent) 24%,var(--_line));background:var(--_accent-soft);color:var(--_accent)}
.pill.info .icon{background:var(--_accent);color:#fff}
.pill.neutral{border-color:var(--_line);background:var(--_soft);color:var(--_muted)}
.pill.neutral .icon{background:var(--_line);color:var(--_muted)}
.count{display:inline-flex;min-width:20px;height:20px;align-items:center;justify-content:center;margin-left:2px;padding:0 6px;border-radius:999px;background:color-mix(in srgb,currentColor 12%,var(--_bg));font-size:10px;font-weight:850}
.empty{padding:36px 22px;color:var(--_muted);font-size:13px;text-align:center}
@media (max-width:520px){.heading{padding:18px}.list{padding:16px}}
@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827;--_accent-soft:#1b2145}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}

`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];

const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const items=Array.isArray(data.items)?data.items:[]; const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Status';
const icons={success:'✓',danger:'✗',warning:'!',info:'•',neutral:'–'}; const frame=make('section','frame'); frame.setAttribute('aria-label',title);
if(data.title||data.subtitle){ const heading=make('header','heading'); heading.appendChild(make('div','eyebrow','At a glance')); heading.appendChild(make('h2','',title)); if(data.subtitle) heading.appendChild(make('div','subtitle',String(data.subtitle))); frame.appendChild(heading); }
if(!items.length){ frame.appendChild(make('div','empty','Add status or category tags to show pills.')); }
else{
  const list=make('div','list'); list.setAttribute('role','list');
  items.forEach((item) => { const tone=item&&icons[item.tone]?item.tone:'neutral'; const pill=make('span','pill '+tone); pill.setAttribute('role','listitem'); if(item&&item.detail) pill.title=String(item.detail); pill.appendChild(make('span','icon',icons[tone])); pill.appendChild(make('span','label',item&&item.label!=null?String(item.label):'Untitled')); if(item&&item.count!=null) pill.appendChild(make('span','count',String(item.count))); list.appendChild(pill); });
  frame.appendChild(list);
}
root.appendChild(frame);

parent.appendChild(host);

